arguments.argument:
//Arm positions
if image_index=0
{
  xOffset=16
  yOffset=11
}
else if image_index=1
{
  xOffset=18
  yOffset=7
}
else if image_index=2
{
  xOffset=20
  yOffset=1
}
else if image_index=3
{
  xOffset=20
  yOffset=-5
}
else if image_index=4
{
  xOffset=17
  yOffset=-11
}
